async function listProblems({ includeComponents = false, limit, difficulty, tags } = {}) {
  // Fetch problems from DB or source
  let problems = await fetchProblemsFromDB();

  // Apply filters
  if (difficulty) {
    problems = problems.filter(p => p.difficulty === difficulty);
  }
  if (tags && tags.length) {
    problems = problems.filter(p => tags.every(t => p.tags.includes(t)));
  }

  // Apply limit
  if (limit) {
    problems = problems.slice(0, limit);
  }

  // Prepare metadata
  const metadata = {};

  if (includeComponents) {
    // Aggregate componentLanguageTotals and componentStatusTotals from filtered & limited problems only
    const componentLanguageTotals = {};
    const componentStatusTotals = {};

    for (const problem of problems) {
      if (!problem.components) continue;
      for (const comp of problem.components) {
        // Deduplicate and sort componentLanguages case-insensitively
        if (comp.componentLanguages && Array.isArray(comp.componentLanguages)) {
          const langs = _.uniqBy(comp.componentLanguages, l => l.toLowerCase()).sort((a, b) =>
            a.toLowerCase().localeCompare(b.toLowerCase())
          );
          for (const lang of langs) {
            componentLanguageTotals[lang] = (componentLanguageTotals[lang] || 0) + 1;
          }
        }
        if (comp.status) {
          componentStatusTotals[comp.status] = (componentStatusTotals[comp.status] || 0) + 1;
        }
      }
    }

    metadata.componentLanguageTotals = componentLanguageTotals;
    metadata.componentStatusTotals = componentStatusTotals;
  }

  return { problems, metadata };
}

module.exports = {
  solve,
  listProblems,
};
